import org.owasp.encoder.Encode;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input before embedding in HTML output
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<head><title>XSS Fixed Demo</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome, " + Encode.forHtml(userInput) + "</h1>"); // User input properly encoded for HTML output
        out.println("</body>");
        out.println("</html>");
    }
}

